## 1. `src/types/pixelmap.ts`

- Add `'groq'` to the `LLMProviderType` union:
```ts
export type LLMProviderType = 'anthropic' | 'openai' | 'openai-compatible' | 'deepseek' | 'groq'
```

- Add a new preset in `PROVIDER_PRESETS`:
```ts
{
  type: 'groq',
  label: 'Groq',
  apiUrl: 'https://api.groq.com/openai/v1',
  model: 'llama3-70b-8192',
},
```

## 2. New file: `src/services/GroqProvider.ts`

Create a class that implements the same HTTP logic as `OpenAIProvider` (Groq uses the same `/v1/chat/completions` endpoint structure).

```ts
import type { PixelGenRequest, PixelMapResponse, Result, AppError } from '@/types/pixelmap'
import type { LLMProvider } from '@/services/providers'
import { parsePixelMapResponse } from '@/services/parseResponse'
import { SYSTEM_PROMPT } from '@/services/constants'

export class GroqProvider implements LLMProvider {
  async generate(request: PixelGenRequest): Promise<Result<PixelMapResponse>> {
    try {
      const response = await fetch(`${request.apiUrl}/v1/chat/completions`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${request.apiKey}`,
        },
        body: JSON.stringify({
          model: request.model,
          max_tokens: 8192,
          messages: [
            { role: 'system', content: SYSTEM_PROMPT },
            { role: 'user', content: request.prompt },
          ],
        }),
      })

      if (!response.ok) {
        const statusText = await response.text().catch(() => response.statusText)
        return {
          ok: false,
          error: {
            message: `API ${response.status}: ${statusText}`,
            code: 'API_ERROR',
            status: response.status,
          } satisfies AppError,
        }
      }

      const data = await response.json()
      const content = data.choices?.[0]?.message?.content
      if (!content) {
        return {
          ok: false,
          error: { message: 'Empty response from Groq API', code: 'PARSE_ERROR' },
        }
      }

      return parsePixelMapResponse(content)
    } catch (err) {
      return {
        ok: false,
        error: {
          message: `Network error: ${err instanceof Error ? err.message : 'Unknown'}`,
          code: 'NETWORK_ERROR',
        },
      }
    }
  }
}
```

## 3. `src/services/llmClient.ts`

- Import the new provider:
```ts
import { GroqProvider } from '@/services/GroqProvider'
```

- Add it to the providers object inside `getProviders()`:
```ts
providers = {
  anthropic: new AnthropicProvider(),
  openai: new OpenAIProvider(),
  'openai-compatible': new OpenAICompatibleProvider(),
  deepseek: new DeepSeekProvider(),
  groq: new GroqProvider(),
}
```

## 4. No changes needed to `ProviderSelect.tsx`

The component already iterates over `PROVIDER_PRESETS` and uses the `LLMProviderType` value, so the new preset will automatically appear in the dropdown.

## 5. No changes needed to `OpenAIProvider.ts` or other existing providers.

The new provider stands on its own and does not reuse their internals. If future refactoring is desired, a base OpenAI‑compatible class could be extracted, but for the current scope the explicit class is sufficient.

